以及說明你心目中理想的酒駕處罰方式。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00139', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於國民教育之敘述，下列何者正確？', '["是一種權利", "目的在於培養服從權威領導的順民", "公民教育應完全由國家主導", "教育只是使國民習得謀生技能，與其人格發展無關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00140', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '下列有關憲法工作權之敘述，何者正確？', '["公務員甲在假日期間至行天宮兼職擔任算命師貼補家用，不屬於工作權保障範圍", "法律規定計程車駕駛必須經考試取得執業證照，屬於對工作權之客觀許可條件之限制", "法律規定律師出庭應穿律師袍，係屬於對職業執行方式之限制", "人民失業有請求國家給予適當工作之權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00141', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法、增修條文及司法院大法官解釋，關於總統機密特權，下列敘述何者錯誤？', '["總統因行使憲法職權而獲得之資訊，如公開可能影響國家安全與國家利益者，總統有決定 不予公開之權力", "總統如以書面釋明，在訴訟程序中公開機密資訊有妨害國家利益之虞，檢察官及法院應予 以尊重，不得駁回總統之決定", "在刑事訴訟程序上，總統就國家機密事項有拒絕證言權", "總統在訴訟程序中公開機密資訊是否有妨害國家利益之虞，應僅由承辦檢察官或審判庭法 官依保密程序為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00142', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依據憲法第137條第2項規定，國防之組織，應如何規定？', '["由三軍統帥訂定命令", "由國防部訂定命令，但須送立法院備查", "由國安會訂定命令，但須送立法院備查", "由立法院制定法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00143', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋，下列有關全民健康保險（下稱全民健保）之敘述，何 者錯誤？', '["憲法增修條文明定國家有實施全民健保的義務", "全民健保是社會保險，但國家亦應尊重國民之個人意願，不得強制國民納保", "全民健保依被保險人的收入，收取不同保險費，符合量能負擔原則", "因全民健保所生對人民權利義務之影響，應有明確規範，並受法律保留原則之拘束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00144', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋意旨，下列何者非屬大學自治之保障內容？', '["關於大學教師薪俸之事項", "直接關涉教學之學術事項", "大學之內部組織自主權", "以成績未達一定標準為由，將學生予以退學"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00145', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院解釋意旨，有關平等權或平等原則之司法審查，下列敘述何者錯誤？', '["法院於適用平等原則時，必須審查差別待遇之目的是否合憲", "憲法第7條以「男女、宗教、種族、階級、黨派」作為差別待遇依據，一律適用嚴格審查 基準", "憲法第7條所定之平等權，係為保障人民在法律上地位之實質平等", "司法院大法官解釋常認平等係指「等者等之，不等者不等之」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00146', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法增修條文第2條之規定，副總統缺位時，總統應如何處理？', '["於3個月內提名候選人，由立法院補選", "於1個月內提名候選人，由行政院院會同意", "於3個月內提名候選人，交由公民補選", "讓副總統維持缺位，不必作任何處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
